import React, { useEffect, useState } from "react";
import axios from "axios";

function ViewProducts() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    axios.get("http://localhost:5000/products")
      .then(res => { setProducts(res.data); setLoading(false); })
      .catch(() => { setError("Could not load products. Is the backend running?"); setLoading(false); });
  }, []);

  const stockBadge = (qty) => {
    if (qty <= 0) return <span className="badge badge-red">Out of Stock</span>;
    if (qty <= 5) return <span className="badge badge-yellow">Low Stock</span>;
    return <span className="badge badge-green">In Stock</span>;
  };

  return (
    <div className="page-enter">
      <div className="page-header">
        <h2>View Products</h2>
        <p>{products.length} items in inventory</p>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      <div className="table-wrapper">
        <table>
          <thead>
            <tr>
              <th>ID</th>
              <th>Product Name</th>
              <th>Quantity</th>
              <th>Price (₹)</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            {loading && (
              <tr><td colSpan="5" className="loading">Loading products...</td></tr>
            )}
            {!loading && products.length === 0 && (
              <tr><td colSpan="5" className="empty">No products found. Add some!</td></tr>
            )}
            {products.map(p => (
              <tr key={p.id}>
                <td style={{ color: "#8888aa" }}>#{p.id}</td>
                <td style={{ fontWeight: 500 }}>{p.name}</td>
                <td>{p.quantity}</td>
                <td>₹{Number(p.price).toLocaleString()}</td>
                <td>{stockBadge(p.quantity)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default ViewProducts;
